import React,{useState} from 'react'
import { Link } from 'react-router-dom'
import {
  CButton,
  CCard,
  CCardBody,
  CCardGroup,
  CCol,
  CContainer,
  CForm,
  CFormInput,
  CInputGroup,
  CInputGroupText,
  CRow,
} from '@coreui/react'
import CIcon from '@coreui/icons-react'
import { cilLockLocked, cilUser } from '@coreui/icons'
import { updateState } from 'src/utils/utils'
import authService from 'src/auth/auth.service'

const Login = () => {
  const [state, setState] = useState({ email: '', password: '' });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [visibility, setVisibility] = useState(false)

  const handleInputChange = (e) => {
    const { name, value } = e.target
    const newState = updateState(state, { [name]: value })
    setState(newState)
  }

  const validateForm = () => {
    let errors = {};
    let formIsValid = true;
    if (!state.email) {
      errors['name'] = "Please enter user email";
      formIsValid = false;
    }
    if (!state.password) {
      errors['password'] = "Please enter password";
      formIsValid = false;
    }
    setErrors(errors);
    setTimeout(() => {
      setErrors("");
    }, 2000);
    return formIsValid;
  }

  const handleLogin = () => {
    if(validateForm()) {
      setLoading(true)
      authService.login(state?.email, state?.password)
        .then(() => {
          window.location.href = '/'
        })
        .catch((error) => {
          setLoading(false);
          // setError(error?.response?.data?.message)
          setError(error?.response?.data?.error)

        })
        setTimeout(() => {
          setError("");
        }, 2000);
    }
  }

  const handleVisibility = () => {
    setVisibility(
      visibility ? false : true
      );
  }

  return (
    <div className="bg-light min-vh-100 d-flex flex-row align-items-center">
      <CContainer>
        <CRow className="justify-content-center">
          <CCol md={4}>
            <CCardGroup>
              <CCard className="p-4">
                <CCardBody>
                  <CForm>
                    <h1>Login</h1>
                    <p className="text-medium-emphasis">Sign In to your account</p>
                    <CInputGroup className="mb-3">
                      <CInputGroupText>
                        <CIcon icon={cilUser} />
                      </CInputGroupText>
                      <CFormInput
                        placeholder="Email"
                        autoComplete="email"
                        name="email"
                        onChange={handleInputChange}
                      />
                    </CInputGroup>

                    <span style={{ color: "red" }}>{errors['name']}</span>
                      <CInputGroup className="mb-3">
                          <CInputGroupText> <CIcon icon={cilLockLocked} /></CInputGroupText>
                          <CFormInput
                            type= {visibility ? "text" : "password"}
                            placeholder="Password"
                            autoComplete="current-password"
                            name="password"
                            onChange={handleInputChange}
                          />
                          <CInputGroupText style={{cursor : "pointer"}} onClick={() => {handleVisibility()}}>{!visibility ? "Show" : "Hide"}</CInputGroupText>
                      </CInputGroup>
                    <span style={{ color: "red" }}>{errors['password']}</span>
                    <div className='form-group mb-3 mt-2'>
                      <span style={{ color: "red" }}>{error}</span>
                    </div>
                    <CRow>
                      <CCol xs={6}>
                        <CButton color="primary" className="px-4" onClick={handleLogin}>
                          Login
                        </CButton>
                      </CCol>
                      <CCol xs={6} className="text-right">
                        <CButton color="link" className="px-0">
                          Forgot password?
                        </CButton>
                      </CCol>
                    </CRow>
                  </CForm>
                </CCardBody>
              </CCard>
              {/* <CCard className="text-white bg-primary py-5" style={{ width: '44%' }}>
                <CCardBody className="text-center">
                  <div>
                    <h2>Sign up</h2>
                    <p>
                      Lorem ipsum dolor sit amet, consectetur adipisicing elit, sed do eiusmod
                      tempor incididunt ut labore et dolore magna aliqua.
                    </p>
                    <Link to="/register">
                      <CButton color="primary" className="mt-3" active tabIndex={-1}>
                        Register Now!
                      </CButton>
                    </Link>
                  </div>
                </CCardBody>
              </CCard> */}
            </CCardGroup>
          </CCol>
        </CRow>
      </CContainer>
    </div>
  )
}

export default Login
